import{_ as o,o as a,c as n,ag as t}from"./chunks/framework.6ZJjlmu_.js";const g=JSON.parse('{"title":"Troubleshooting & FAQ","description":"","frontmatter":{},"headers":[],"relativePath":"troubleshooting/faq.md","filePath":"troubleshooting/faq.md"}'),r={name:"troubleshooting/faq.md"};function s(i,e,l,d,c,h){return a(),n("div",null,[...e[0]||(e[0]=[t('<h1 id="troubleshooting-faq" tabindex="-1">Troubleshooting &amp; FAQ <a class="header-anchor" href="#troubleshooting-faq" aria-label="Permalink to &quot;Troubleshooting &amp; FAQ&quot;">​</a></h1><h2 id="i-see-no-rows-at-all" tabindex="-1">I see no rows at all <a class="header-anchor" href="#i-see-no-rows-at-all" aria-label="Permalink to &quot;I see no rows at all&quot;">​</a></h2><ol><li><strong>Play Mode</strong> — Event Monitor is aimed at Play sessions (timestamps and frame info assume runtime).</li><li><strong>Record</strong> — Ensure the toolbar <strong>Record</strong> toggle is on.</li><li><strong>ILPP</strong> — Confirm <code>recordingEnabled</code> is not <code>false</code> in <code>Library/EventMonitor/ilpp_settings.json</code>. Enable <a href="./../how-to/ilpp-diagnostics.html">ILPP diagnostics</a> and recompile.</li><li><strong>Code path</strong> — Trigger a known <code>+=</code> or <code>?.Invoke()</code> in an <strong>instrumented</strong> assembly.</li></ol><h2 id="sub-appears-but-invoke-never-does" tabindex="-1">SUB appears but INVOKE never does <a class="header-anchor" href="#sub-appears-but-invoke-never-does" aria-label="Permalink to &quot;SUB appears but INVOKE never does&quot;">​</a></h2><ul><li><strong>Null delegate</strong> — <code>?.Invoke()</code> does not call <code>Invoke</code> when there are no subscribers; no injection site runs.</li><li><strong>Filter</strong> — Clear the log <strong>search</strong> field; disable overly narrow filters. See <a href="./../how-to/filtering-and-missing-invoke.html">Filtering and missing INVOKE rows</a>.</li><li><strong>Pattern</strong> — Firing through helpers may skip the injector. See <a href="./../reference/il-limitations.html">IL patterns and limitations</a>.</li></ul><h2 id="duplicate-or-extra-sub-unsub-lines" tabindex="-1">Duplicate or “extra” SUB/UNSUB lines <a class="header-anchor" href="#duplicate-or-extra-sub-unsub-lines" aria-label="Permalink to &quot;Duplicate or “extra” SUB/UNSUB lines&quot;">​</a></h2><p><strong>ReflectionScanner</strong> plus ILPP can both observe subscription changes. See <a href="./../concepts/ilpp-vs-reflection-scanner.html">ILPP vs ReflectionScanner</a>.</p><h2 id="payload-always-empty" tabindex="-1">Payload always empty <a class="header-anchor" href="#payload-always-empty" aria-label="Permalink to &quot;Payload always empty&quot;">​</a></h2><ul><li>Turn <strong>Payload</strong> on in the toolbar.</li><li>Ensure <code>EnablePayloadCapture</code> is effectively true for the session.</li><li>For non-instrumented invocations, use <code>TagPayload</code> immediately before firing.</li></ul><h2 id="performance-concerns" tabindex="-1">Performance concerns <a class="header-anchor" href="#performance-concerns" aria-label="Permalink to &quot;Performance concerns&quot;">​</a></h2><ul><li>Keep <strong>Payload</strong> and <strong>Stack Traces</strong> off unless needed.</li><li>Avoid <strong>Payload Details</strong> on large object graphs during long Play sessions.</li></ul><h2 id="where-is-the-demo-scene" tabindex="-1">Where is the demo scene? <a class="header-anchor" href="#where-is-the-demo-scene" aria-label="Permalink to &quot;Where is the demo scene?&quot;">​</a></h2><p><strong>Tools → Event Monitor → Generate Demo Scene</strong> — see <a href="./../how-to/demo-scene.html">Generate the demo scene</a>.</p><h2 id="full-documentation-index" tabindex="-1">Full documentation index <a class="header-anchor" href="#full-documentation-index" aria-label="Permalink to &quot;Full documentation index&quot;">​</a></h2><p>Start at <a href="/apps/public/eventmonitor/">Overview</a> or <a href="./../guide/quick-start.html">Quick Start</a>.</p>',15)])])}const m=o(r,[["render",s]]);export{g as __pageData,m as default};
